import { useEffect, useState } from 'react';
import { useSocket } from '../../context/SocketContext';
import IncidentCard from '../../components/IncidentCard';

export default function VolunteerDashboard() {
  const [incidents, setIncidents] = useState([]);
  const socket = useSocket();

  useEffect(() => {
    if (socket) {
      socket.on('NEW_EMERGENCY', (data) => setIncidents(prev => [data, ...prev]));
    }
  }, [socket]);

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Nearby Rescue Requests</h1>
      <div className="grid gap-4 max-w-2xl">
        {incidents.map(inc => <IncidentCard key={inc.incidentId} incident={inc} onAccept={(id) => alert(`Accepting ${id}`)} />)}
        {incidents.length === 0 && <div className="py-20 text-center text-gray-400">Searching for reports...</div>}
      </div>
    </div>
  );
}
